parameters.jsCode:
const timestamp = new Date().toISOString();
const studentId = $('Student Status Agent').first().json.output.studentId;
const lifecycleStage = $('Student Status Agent').first().json.output.lifecycleStage;
const actionType = $('Academic Orchestration Agent').first().json.output.actionType;
const priority = $('Academic Orchestration Agent').first().json.output.overallPriority;

const logEntry = {
  timestamp,
  studentId,
  lifecycleStage,
  actionType,
  priority,
  orchestrationSummary: $('Academic Orchestration Agent').first().json.output.orchestrationSummary,
  workflowStatus: "COMPLETED"
};

console.log("Workflow Completion Log:", JSON.stringify(logEntry, null, 2));

return [{ json: logEntry }];
